import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_travel_time(pos1, pos2, speed):
        return np.linalg.norm(np.array(pos1) - np.array(pos2)) / speed

    def calculate_score(travel_time, customer_index):
        arrival_time = current_time + travel_time
        start_window, end_window = time_windows[customer_index]

        if arrival_time > end_window:
            return float('inf')  # Return a high penalty for missing the time window

        if arrival_time < start_window:
            wait_time = start_window - arrival_time
        else:
            wait_time = 0

        # Weight considerations: urgency as 1/time to end of window, distance is travel_time, and wait penalty is wait_time
        urgency = 1.0 / (end_window - current_time) if end_window > current_time else float('inf')
        return travel_time + 2 * wait_time - urgency

    best_node = None
    best_score = float('inf')

    for index, customer_pos in enumerate(unvisited_customers):
        travel_time = calculate_travel_time(cur_truck_pos, customer_pos, truck_speed)
        score = calculate_score(travel_time, index)

        if score < best_score:
            best_score = score
            best_node = index

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def euclidean_distance(pos1, pos2):
        return np.linalg.norm(pos1 - pos2)

    def calculate_arrival_time(distance, current_time, speed):
        return current_time + (distance / speed)

    scores = []

    for i, customer_pos in enumerate(unvisited_customers):
        distance = euclidean_distance(cur_truck_pos, customer_pos)
        arrival_time = calculate_arrival_time(distance, current_time, truck_speed)

        time_window_start, time_window_end = time_windows[i]

        if arrival_time > time_window_end:
            scores.append(float('inf'))  # Penalize missing the time window
        else:
            wait_time = max(0, time_window_start - arrival_time)
            urgency_penalty = (time_window_end - current_time) / (1 + wait_time)
            score = distance + urgency_penalty
            scores.append(score)

    best_node = np.argmin(scores)
    return best_node

