import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    min_score = float('inf')
    best_node = None

    def euclidean_distance(p1, p2):
        return np.linalg.norm(p1 - p2)

    for idx, customer_pos in enumerate(unvisited_customers):
        travel_time = euclidean_distance(cur_truck_pos, customer_pos) / truck_speed
        arrival_time = current_time + travel_time
        start_window, end_window = time_windows[idx]

        if arrival_time > end_window:
            score = float('inf')  # Penalize if the customer cannot be reached in time
        else:
            wait_time = max(0, start_window - arrival_time)
            lateness_penalty = max(0, arrival_time - end_window)

            # Score calculation: balance between distance, wait time, and proximity to window expiry
            score = travel_time + wait_time + 2 * lateness_penalty + (end_window - arrival_time)

        if score < min_score:
            min_score = score
            best_node = idx

    if best_node is None:
        best_node = np.argmin([euclidean_distance(cur_truck_pos, depot_pos) for _ in unvisited_customers])

    return best_node
